                r, c = r0, c0
                step = 0
                while 1 <= r + dr <= 8 and 1 <= c + dc <= 8:
                    r += dr
                    c += dc
                    step += 1
                    res.append((dr, dc, step))
            return res

        all_moves = [moves_for(i) for i in range(n)]
        count = 0

        def simulate(chosen):
            max_t = max(m[2] for m in chosen)
            for t in range(max_t + 1):
                seen = set()
                for i, (dr, dc, steps) in enumerate(chosen):
                    s = min(t, steps)
                    r0, c0 = positions[i]
                    p = (r0 + dr * s, c0 + dc * s)
                    if p in seen:
                        return False
                    seen.add(p)
            return True

        chosen = []

        def backtrack(i):
            nonlocal count
            if i == n:
                if simulate(chosen):
                    count += 1
                return
            for mv in all_moves[i]:
                chosen.append(mv)
                backtrack(i + 1)
                chosen.pop()

